qry:select.qry:xquery:
for $r in sql('
	SELECT TTA07_FICHADASING.oi_personal_emp, 
	MAX(TTA07_FICHADASING.f_fechahora) AS f_fechahora,
	ORG02_ESTRUC_PERS.oi_estructura
	FROM TTA07_FICHADASING, ORG02_ESTRUC_PERS
	JOIN TTA07_FICHADASING.oi_personal_emp INNER ORG02_ESTRUC_PERS.oi_personal_emp
	WHERE ORG02_ESTRUC_PERS.oi_clase_org in ({%=string(#ORGANIGRAMAS:CLASES/CLASE/@oi_clase_org)%})
	{%? (string(#FILTRO:ESTRUCTURAS/ESTRUCTURA/@id)!='') 
	{% AND ORG02_ESTRUC_PERS.oi_estructura in ({%=string(#FILTRO:ESTRUCTURAS/ESTRUCTURA/@id)%}) %} 
	{%  %} 
	%}
	{%? (string(#FILTRO:PERSONAS/PERSONA/@id)!='') 
		{% AND TTA07_FICHADASING.oi_personal_emp in ({%=string(#FILTRO:PERSONAS/PERSONA/@id)%}) %} 
		{%  %} 
	%}			
	GROUP BY TTA07_FICHADASING.oi_personal_emp, ORG02_ESTRUC_PERS.oi_estructura
	ORDER BY oi_estructura ASC, oi_personal_emp ASC
')/ROWS/ROW
